#include <bits/stdc++.h>
using namespace std;
const int N=2e6+6;
int n,m,a[N],t[4*N];
void build(int cur,int l,int r){
    if(l==r){
        t[cur]=a[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=min(t[cur*2],t[cur*2+1]);
}
int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1,ans=1e9;
    if(x<=mid)
        ans=min(ans,query(cur*2,l,mid,x,y));
    if(y>mid)
        ans=min(ans,query(cur*2+1,mid+1,r,x,y));
    return ans;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    build(1,1,n);
    puts("0");
    for(int i=2;i<=n;i++)
        printf("%d\n",query(1,1,n,max(1,i-m),i-1));
    return 0;
}
